"use strict";(self.webpackChunkmif_docs=self.webpackChunkmif_docs||[]).push([[7865],{1053(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Dev \ud83d\udea7","banner":"unreleased","badge":true,"noIndex":false,"className":"docs-version-current","isLast":false,"docsSidebars":{"docs":[{"type":"category","label":"Getting Started","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/docs/dev/getting-started/prerequisites","label":"Prerequisites","docId":"getting-started/prerequisites","unlisted":false},{"type":"link","href":"/docs/dev/getting-started/quickstart","label":"Quickstart","docId":"getting-started/quickstart","unlisted":false}]},{"type":"category","label":"Features","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/docs/dev/features/preset","label":"Presets","docId":"features/preset","unlisted":false},{"type":"link","href":"/docs/dev/features/prefill-decode-disaggregation","label":"PD Disaggregation","docId":"features/prefill-decode-disaggregation","unlisted":false},{"type":"link","href":"/docs/dev/features/prefix-cache-aware-routing","label":"Prefix Cache-aware Routing","docId":"features/prefix-cache-aware-routing","unlisted":false}]},{"type":"category","label":"Operations","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/docs/dev/operations/latest-release","label":"Latest Release","docId":"operations/latest-release","unlisted":false},{"type":"category","label":"Monitoring","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/docs/dev/operations/monitoring/metrics/","label":"Metrics","docId":"operations/monitoring/metrics/index","unlisted":false},{"type":"link","href":"/docs/dev/operations/monitoring/logs/","label":"Logs","docId":"operations/monitoring/logs/index","unlisted":false},{"type":"link","href":"/docs/dev/operations/monitoring/traces/","label":"Traces","docId":"operations/monitoring/traces/index","unlisted":false}]},{"type":"link","href":"/docs/dev/operations/hf-model-management-with-pv","label":"HF Model Management (PV)","docId":"operations/hf-model-management-with-pv","unlisted":false},{"type":"link","href":"/docs/dev/operations/multi-model","label":"Multi-model Serving","docId":"operations/multi-model","unlisted":false},{"type":"link","href":"/docs/dev/operations/container-image-caching-with-harbor/","label":"Container image caching (Harbor)","docId":"operations/container-image-caching-with-harbor/index","unlisted":false}]},{"type":"category","label":"Reference","collapsible":true,"collapsed":false,"items":[{"type":"category","label":"Heimdall","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/docs/dev/reference/heimdall/api-reference","label":"API Reference","docId":"reference/heimdall/api-reference","unlisted":false},{"type":"link","href":"/docs/dev/reference/heimdall/plugins","label":"Plugins","docId":"reference/heimdall/plugins","unlisted":false}]},{"type":"category","label":"Heimdall AIGateway","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/docs/dev/reference/heimdall-aigateway/usage","label":"Usage","docId":"reference/heimdall-aigateway/usage","unlisted":false},{"type":"link","href":"/docs/dev/reference/heimdall-aigateway/plugins","label":"Plugins","docId":"reference/heimdall-aigateway/plugins","unlisted":false}]},{"type":"category","label":"Odin","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/docs/dev/reference/odin/api-reference","label":"API Reference","docId":"reference/odin/api-reference","unlisted":false}]},{"type":"link","href":"/docs/dev/reference/supported-devices","label":"Supported devices","docId":"reference/supported-devices","unlisted":false}]}]},"docs":{"features/prefill-decode-disaggregation":{"id":"features/prefill-decode-disaggregation","title":"Prefill-Decode Disaggregation","description":"During LLM inference, computation occurs in two stages: prefill and decode. In the prefill phase, the model processes the entire input prompt to generate the first token &mdash; a highly parallel, compute-bound process. The decode phase then predicts one token at a time, reusing the growing KV cache, and is memory-bound.","sidebar":"docs"},"features/prefix-cache-aware-routing":{"id":"features/prefix-cache-aware-routing","title":"Prefix Cache-aware Routing","description":"Prefix caching is a technique that stores the KV cache from previous queries, allowing subsequent queries with an identical prefix to reuse it. This eliminates redundant computation and significantly improves performance for workloads with common prefixes, such as system prompts, conversation history, or shared contextual documents.","sidebar":"docs"},"features/preset":{"id":"features/preset","title":"Presets","description":"The MoAI Inference Framework provides a set of pre-configured InferenceServiceTemplates, known as presets. These presets encapsulate standard configurations for various models and hardware setups, simplifying the deployment of inference services.","sidebar":"docs"},"getting-started/prerequisites":{"id":"getting-started/prerequisites","title":"Prerequisites","description":"This document introduces the prerequisites for the MoAI Inference Framework and provides instructions on how to install them.","sidebar":"docs"},"getting-started/quickstart":{"id":"getting-started/quickstart","title":"Quickstart","description":"This quickstart launches two vLLM instances (pods) of the Llama 3.2 1B Instruct model and serves them through a single AI Gateway endpoint as an example. Please make sure to install all prerequisites before starting this quickstart guide. The prerequisites install cert-manager, the infrastructure bundle, the required CRDs, and the Odin and Heimdall operators that this guide builds on.","sidebar":"docs"},"operations/container-image-caching-with-harbor/index":{"id":"operations/container-image-caching-with-harbor/index","title":"Container image caching with Harbor","description":"The container images composing the MoAI Inference Framework are distributed through Amazon ECR. Although this approach works well in general, fetching images from a remote registry during deployment and scaling of inference environments may incur substantial delays.","sidebar":"docs"},"operations/hf-model-management-with-pv":{"id":"operations/hf-model-management-with-pv","title":"Hugging Face model management with persistent volume","description":"Efficient management of large language models (LLMs) is crucial for optimizing storage usage and reducing startup times. Instead of downloading models repeatedly for each pod, using a shared Persistent Volume (PV) allows multiple pods to access the same model files.","sidebar":"docs"},"operations/latest-release":{"id":"operations/latest-release","title":"Latest release","description":"The following table lists the latest released versions of MIF components and their bundled dependencies. The MIF charts are published to the moreh Helm repository (https://moreh-dev.github.io/helm-charts).","sidebar":"docs"},"operations/monitoring/logs/index":{"id":"operations/monitoring/logs/index","title":"Log Collection (Loki + Vector)","description":"This document explains how to enable centralized log collection for the MoAI Inference Framework using Loki (log aggregation) and Vector (log collection agent).","sidebar":"docs"},"operations/monitoring/metrics/index":{"id":"operations/monitoring/metrics/index","title":"Metrics Monitoring","description":"This document describes how to access Grafana dashboards to monitor the MoAI Inference Framework and provides an overview of the available metrics. Please make sure to install all prerequisites before starting this monitoring guide.","sidebar":"docs"},"operations/monitoring/traces/index":{"id":"operations/monitoring/traces/index","title":"Trace Monitoring (Tempo)","description":"The MoAI Inference Framework bundles Grafana Tempo for distributed tracing. The Heimdall AI Gateway emits OpenTelemetry traces that show how it routes and schedules each request, and the moai-inference-framework chart provisions Tempo as a Grafana data source automatically. This guide shows how to view those traces in Grafana.","sidebar":"docs"},"operations/multi-model":{"id":"operations/multi-model","title":"Multi-model serving","description":"Multi-model serving enables serving multiple models through a single endpoint, routing requests to the appropriate model based on the model field in the request body. By combining the Body-Based Router (BBR) with Heimdall schedulers, the MoAI Inference Framework can serve multiple models across different GPU types through a unified API.","sidebar":"docs"},"reference/heimdall-aigateway/plugins":{"id":"reference/heimdall-aigateway/plugins","title":"Plugins","description":"A SchedulingProfile composes the gateway\'s routing decision from scorer and picker plugins. Scorers assign a score to each candidate inference pod; the picker selects a destination from the scored candidates. Each plugin is declared once under spec.plugins and referenced (with an optional weight) from a profile\'s pluginRefs.","sidebar":"docs"},"reference/heimdall-aigateway/usage":{"id":"reference/heimdall-aigateway/usage","title":"Usage","description":"Heimdall AIGateway is the request entrypoint of the MoAI Inference Framework. The Heimdall operator runs the gateway from an AIGateway resource, and the gateway routes each request to an inference pod according to a SchedulingProfile. This page documents the custom resources an operator works with.","sidebar":"docs"},"reference/heimdall/api-reference":{"id":"reference/heimdall/api-reference","title":"Heimdall API Reference","description":"inference.networking.k8s.io/v1","sidebar":"docs"},"reference/heimdall/plugins":{"id":"reference/heimdall/plugins","title":"Heimdall plugins","description":"All plugins are declared in the top-level plugins list of EndpointPickerConfig. Heimdall assigns each plugin to the appropriate extension point based on the interfaces it implements. A single plugin can implement multiple interfaces (for example, context-length-aware acts as both a Filter and a Scorer; active-request-scorer acts as both a Scorer and a response lifecycle hook).","sidebar":"docs"},"reference/odin/api-reference":{"id":"reference/odin/api-reference","title":"Odin API Reference","description":"odin.moreh.io/v1alpha1","sidebar":"docs"},"reference/supported-devices":{"id":"reference/supported-devices","title":"Supported devices","description":"Accelerator labels","sidebar":"docs"}}}}')}}]);